output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?season ?start ?end WHERE {
  wd:Q7981951 wdt:P3416 ?season .
  ?season wdt:P580 ?start ; wdt:P582 ?end
}

args.sparql:
SELECT ?season ?seasonLabel ?start ?end WHERE {
  wd:Q7981951 wdt:P3416 ?season .
  ?season wdt:P580 ?start ;
          wdt:P582 ?end .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en" }
}
